package com.variable;

public class Swap {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		        int a = 3;
		        int b = 5;

		        a = a + b;
		        b = a - b;
		        a = a - b;

		        System.out.println(a);
		        System.out.println(b);
		    

	}

}
